// A $( document ).ready() block.
$(document).ready(function() {

    function toSlug(str) {
        // Chuyل»ƒn hل؛؟t sang chل»¯ thئ°ل»‌ng
        str = str.toLowerCase();     
     
        // xأ³a dل؛¥u
        str = str.replace(/(أ |أ،|ل؛،|ل؛£|أ£|أ¢|ل؛§|ل؛¥|ل؛­|ل؛©|ل؛«|ؤƒ|ل؛±|ل؛¯|ل؛·|ل؛³|ل؛µ)/g, 'a');
        str = str.replace(/(أ¨|أ©|ل؛¹|ل؛»|ل؛½|أھ|ل»پ|ل؛؟|ل»‡|ل»ƒ|ل»…)/g, 'e');
        str = str.replace(/(أ¬|أ­|ل»‹|ل»‰|ؤ©)/g, 'i');
        str = str.replace(/(أ²|أ³|ل»چ|ل»ڈ|أµ|أ´|ل»“|ل»‘|ل»™|ل»•|ل»—|ئ،|ل»‌|ل»›|ل»£|ل»ں|ل»،)/g, 'o');
        str = str.replace(/(أ¹|أ؛|ل»¥|ل»§|إ©|ئ°|ل»«|ل»©|ل»±|ل»­|ل»¯)/g, 'u');
        str = str.replace(/(ل»³|أ½|ل»µ|ل»·|ل»¹)/g, 'y');
        str = str.replace(/(ؤ‘)/g, 'd');
     
        // Xأ³a kأ½ tل»± ؤ‘ل؛·c biل»‡t
        str = str.replace(/([^0-9a-z-\s])/g, '');
     
        // Xأ³a khoل؛£ng trل؛¯ng thay bل؛±ng kأ½ tل»± -
        str = str.replace(/(\s+)/g, '-');
        
        // Xأ³a kأ½ tل»± - liأھn tiل؛؟p
        str = str.replace(/-+/g, '-');
     
        // xأ³a phل؛§n dل»± - ل»ں ؤ‘ل؛§u
        str = str.replace(/^-+/g, '');
     
        // xأ³a phل؛§n dئ° - ل»ں cuل»‘i
        str = str.replace(/-+$/g, '');
     
        // return
        return str;
    }

    $('.deleteProductAction').click(function (){
        var id = $(this).attr('value')
        var cate = $('.cate').attr('value')
        $("#deleteProduct").attr("href", "http://localhost/ThreeTech/san-pham/xoa/"+id+"/"+cate)
    })

    $('.auto-url').click(function(){
        var tenSanPham =  $(".tenSanPham").val()
        const duongDan = toSlug(tenSanPham)
        $(".duongDan").val(duongDan)
    })
});